}
```

## 过滤器优先级

```cpp
int IsFilterSegment(VirtualMemoryArea& vma) {
    if (FILTER_SPECIAL_VMA && isSpecialDevice(vma))
        return VMA_NULL;

    if (FILTER_FILE_VMA && inode > 0 && isFileBacked(vma))
        return NeedFilterFile(vma);

    if (FILTER_SHARED_VMA && isShared(vma))
        return VMA_NULL;

    // ... more filters
}
```

