    └───────────────────────┘
```

## 详细时序图

```
Thread A                    OpenCore                    Kernel
  │                            │                           │
  │─ SIGSEGV ─────────────────>│                           │
  │                            │                           │
  │                            │─ Disable() ─────────────>│
  │                            │  (卸载处理器)              │
  │                            │                           │
  │                            │─ fork() ─────────────────>│
  │                            │   │                       │
  │                            │<── child_pid ─────────────│
  │                            │   │                       │
  │                            │   │─ ptrace(ATTACH) ────>│
  │                            │   │─ wait()              │
  │                            │   │                       │
  │                            │   │─ Write ELF Core ─────>│
  │                            │   │                       │
  │                            │<── exit(0) ──────────────│
  │                            │                           │
  │<── raise(SIGSEGV) ─────────│                           │
  │                            │                           │
  │─ (系统默认处理: 终止) ────>│                           │
```

## Enable 源码分析

```cpp
// opencore.cpp:72-104
bool Opencore::Enable() {
    pthread_mutex_lock(&g_switch_lock);
    if (handlers_installed) {
        JNI_LOGW("opencore native handlers already installed.");
        pthread_mutex_unlock(&g_switch_lock);
        return false;
    }

    // 1. 保存原有信号处理
    for (int i = 0; i < kNumHandledSignals; ++i) {
        if (sigaction(kExceptionSignals[i], NULL, &g_restore_action[i]) == -1) {
            JNI_LOGE("signal %d unable to store old handler", kExceptionSignals[i]);
            pthread_mutex_unlock(&g_switch_lock);
            return false;
        }
    }

    // 2. 配置新处理器
    struct sigaction stact;
    memset(&stact, 0, sizeof(stact));
    sigemptyset(&stact.sa_mask);

    for (int i = 0; i < kNumHandledSignals; ++i)
        sigaddset(&stact.sa_mask, kExceptionSignals[i]);

    stact.sa_sigaction = Opencore::HandleSignal;
    stact.sa_flags = SA_RESTART | SA_SIGINFO | SA_ONSTACK;  // 关键标志

    // 3. 安装处理器
    for (int i = 0; i < kNumHandledSignals; i++)
        sigaction(kExceptionSignals[i], &stact, NULL);

    handlers_installed = true;
    pthread_mutex_unlock(&g_switch_lock);
    return true;
}
```

## HandleSignal 源码分析

```cpp
// opencore.cpp:64-70
void Opencore::HandleSignal(int signal, siginfo_t* siginfo, void* ucontext_raw) {
    pthread_mutex_lock(&g_handle_lock);  // 互斥锁
    Disable();                           // 关键：先卸载
    Dump(siginfo, ucontext_raw);         // 生成 core
    raise(signal);                       // 恢复原处理
    pthread_mutex_unlock(&g_handle_lock);
}
```

## 关键设计点

| 设计 | 目的 |
|------|------|
| `pthread_mutex_lock` | 防止同一信号多次触发导致重复 dump |
| `Disable()` 先于 `Dump()` | 确保不会重复进入 dump 流程 |
| `SA_ONSTACK` | 使用独立信号栈，避免栈溢出导致无法处理 |
| `SA_SIGINFO` | 获取 siginfo 和 ucontext |
| `fork()` + `wait()` | 子进程执行实际 dump，父进程等待 |

## 处理信号列表

```cpp
static constexpr int kExceptionSignals[] = {
    SIGSEGV,  // 段错误 - 内存访问违规
    SIGABRT,  // 中止 - abort() 调用
    SIGFPE,   // 浮点异常 - 数学运算错误
    SIGILL,   // 非法指令 - CPU 不支持指令
    SIGBUS,   // 总线错误 - 对齐/访问错误
    SIGTRAP   // 陷阱 - 断点/跟踪
};
```

## 子进程 dump 流程

```cpp
// opencore.cpp:373-388
bool Opencore::Coredump(const char* filename) {
    pid_t child = fork();
    if (child == 0) {
        IgnoreHandler();              // 子进程忽略信号
        signal(SIGALRM, TimeoutHandle);
        alarm(getTimeout());          // 超时保护
        DoCoredump(filename);        // 架构特定实现
        Finish();
        _exit(0);
    } else {
        JNI_LOGI("Wait (%d) coredump", child);
        int status = 0;
        wait(&status);
    }
    return true;
}
```

## 超时处理

```cpp
// opencore.cpp:170-175
void Opencore::TimeoutHandle(int) {
    JNI_LOGI("Coredump timeout.");
    Opencore* impl = GetInstance();
    if (impl) impl->Finish();
    _exit(0);
}
```

